// This file was generated by Slater.app - CleverMellow 2.0
// Modified: loads from local assets/slater/ instead of slater.app

var paths = window.location.pathname.split('/');

var revealLocalPreview = function() {
  document.querySelectorAll('.page_loader_wrap').forEach(function(loader) {
    loader.style.display = 'none';
    loader.style.opacity = '0';
    loader.style.visibility = 'hidden';
  });
  document.querySelectorAll('header, section, nav').forEach(function(el) {
    el.style.translate = '0rem 0rem';
    el.style.transform = '';
  });
};

// Resolve the base path for local slater scripts
function getBase() {
  var scripts = document.querySelectorAll('script[src*="7804.js"]');
  if (scripts.length) {
    var src = scripts[scripts.length - 1].getAttribute('src');
    return src.replace('7804.js', '') + 'slater/';
  }
  return 'assets/slater/';
}

var BASE = getBase();

function loadLocal(filename) {
  return new Promise(function(resolve) {
    var s = document.createElement('script');
    s.src = BASE + filename + '?v=1';
    s.onload = resolve;
    s.onerror = function(e) {
      console.warn('Could not load local script:', filename, e);
      resolve();
    };
    document.body.appendChild(s);
  });
}

// Hard fallback — if loader still showing after 4s, just reveal
window.addEventListener('load', function() {
  setTimeout(function() {
    var loader = document.querySelector('.page_loader_wrap');
    if (loader && getComputedStyle(loader).display !== 'none') {
      revealLocalPreview();
    }
  }, 4000);
});

var p    = paths[paths.length - 1];
var ip   = paths[paths.length - 2];
var isHome = (p === '' || p === 'index.html');

document.addEventListener('DOMContentLoaded', function() {
  // Load order matters:
  //  1. pageloader  — sets up cm:init listener
  //  2. lightbars   — sets up cm:new_case listener
  //  3. scramble    — hover effects
  //  4. home_cases / home_components (home only)
  //  5. __main_new  — LAST, triggers cm:init

  var chain = loadLocal('pageloader.js')
    .then(function() { return loadLocal('_lightbars.js'); })
    .then(function() { return loadLocal('_scramble.js'); });

  if (isHome) {
    chain = chain
      .then(function() { return loadLocal('home_cases.js'); })
      .then(function() { return loadLocal('home_components.js'); });
  }

  chain
    .then(function() { return loadLocal('__main_new.js'); })
    .catch(function(err) {
      console.warn('Slater bundle error:', err);
      revealLocalPreview();
    });
});
